import numpy as np
import scipy.ndimage

# --------------------------------------------------------------------------- #
# Helper utilities
# --------------------------------------------------------------------------- #
def _is_empty(x):
    """Return True if *x* is None or has no elements."""
    if x is None:
        return True
    if isinstance(x, np.ndarray):
        return x.size == 0
    try:
        return len(x) == 0
    except Exception:
        return False


# --------------------------------------------------------------------------- #
# Rotate2D task
# --------------------------------------------------------------------------- #
class Rotate2D:
    """
    Rotate a square 2‑D image by a given angle.

    Parameters
    ----------
    order : int, optional
        Interpolation order for generic rotation (default 1, bilinear).
    mode : str, optional
        How the input array is extended beyond its boundaries
        (default 'constant').
    reshape : bool, optional
        Keep the output array the same shape as the input
        (default False).
    """

    def __init__(self, **kwargs):
        self.order = kwargs.get("order", 1)
        self.mode = kwargs.get("mode", "constant")
        self.reshape = kwargs.get("reshape", False)
        self.cval = kwargs.get("cval", 0.0)

    # --------------------------------------------------------------------- #
    # Problem generation
    # --------------------------------------------------------------------- #
    def generate_problem(self, n, random_seed=1):
        rng = np.random.default_rng(random_seed)
        image = rng.random((n, n), dtype=np.float32) * 255.0
        angle = float(rng.uniform(-180.0, 180.0))
        return {"image": image, "angle": angle}

    # --------------------------------------------------------------------- #
    # Helper methods
    # --------------------------------------------------------------------- #
    def _fast_rot90(self, img, k):
        return np.rot90(img, k=k)

    def _generic_rotate(self, img, angle):
        # Normalise angle to [-180, 180)
        angle = ((angle + 180.0) % 360.0) - 180.0
        return scipy.ndimage.rotate(
            img,
            angle,
            reshape=self.reshape,
            order=self.order,
            mode=self.mode,
            cval=self.cval,
            prefilter=False,
        )

    # --------------------------------------------------------------------- #
    # Solver
    # --------------------------------------------------------------------- #
    def solve(self, problem):
        img, ang = problem["image"], problem["angle"]
        if abs(ang) < 1e-8:
            rot = img
        elif abs(ang - 90.0) < 1e-6:
            rot = self._fast_rot90(img, 1)
        elif abs(ang + 90.0) < 1e-6:
            rot = self._fast_rot90(img, -1)
        elif abs(ang - 180.0) < 1e-6 or abs(ang + 180.0) < 1e-6:
            rot = self._fast_rot90(img, 2)
        else:
            try:
                rot = self._generic_rotate(img, ang)
            except Exception as exc:
                return {"rotated_image": []}
        return {"rotated_image": rot, "reference": rot}

    # --------------------------------------------------------------------- #
    # Verification
    # --------------------------------------------------------------------- #
    def is_solution(self, problem, solution):
        if not all(k in problem for k in ("image", "angle")):
            return False
        if not isinstance(solution, dict) or "rotated_image" not in solution:
            return False

        img, ang = problem["image"], problem["angle"]
        prop = solution["rotated_image"]

        if _is_empty(prop):
            ref = solution.get("reference")
            return ref is not None and ref.size == 0

        prop_arr = np.asarray(prop, dtype=np.float32)
        if prop_arr.shape != img.shape or not np.all(np.isfinite(prop_arr)):
            return False

        ref_arr = solution.get("reference")
        if ref_arr is None:
            try:
                ref_arr = self._generic_rotate(img, ang)
            except Exception:
                return False

        return np.allclose(prop_arr, ref_arr, rtol=1e-5, atol=1e-7)


# --------------------------------------------------------------------------- #
# Entry point used by the evaluation harness
# --------------------------------------------------------------------------- #
def run_solver(problem):
    """Convenience wrapper that creates a task instance and solves the problem."""
    return Rotate2D().solve(problem)

